const LIGHT_THEME='light';const DARK_THEME='dark';function getValidThemeFromStorage(){let theme=localStorage.getItem('docs-theme')||DARK_THEME;return(theme===LIGHT_THEME||theme===DARK_THEME)?theme:DARK_THEME}
function bgOnLoad(){let theme=getValidThemeFromStorage();let currentTheme=$('head link#theme').attr('href');let storedTheme='static/css/'+theme+'.min.css';if(currentTheme!==storedTheme){$('head link#theme').attr('href','static/css/'+theme+'.min.css')}}
function fabOnClick(){let theme=getValidThemeFromStorage();let newTheme=(theme===LIGHT_THEME)?DARK_THEME:LIGHT_THEME;$('head link#theme').attr('href','static/css/'+newTheme+'.min.css');localStorage.setItem('docs-theme',newTheme)}